1	/** A live cell's position on the infinite grid as [x, y] coordinates. */
2	export type Cell = [number, number];
3	
4	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
5	  [-1, -1], [-1, 0], [-1, 1],
6	  [ 0, -1],          [ 0, 1],
7	  [ 1, -1], [ 1, 0], [ 1, 1],
8	];
9	
10	const neighborsOf = ([x, y]: Cell): Cell[] =>
11	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
12	
13	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
14	const keyToCell = (k: string): Cell =>
15	  k.split(",").map(Number) as [number, number];
16	
17	const tallyLiveNeighbors = (cells: Cell[]): Map<string, number> => {
18	  const counts = new Map<string, number>();
19	  for (const cell of cells) {
20	    for (const neighbor of neighborsOf(cell)) {
21	      const key = cellKey(neighbor);
22	      counts.set(key, (counts.get(key) ?? 0) + 1);
23	    }
24	  }
25	  return counts;
26	};
27	
28	/**
29	 * Computes the next generation of live cells in Conway's Game of Life.
30	 *
31	 * @param cells - The currently live cells on the infinite grid.
32	 * @returns The live cells in the next generation.
33	 */
34	export function nextGeneration(cells: Cell[]): Cell[] {
35	  const liveKeys = new Set(cells.map(cellKey));
36	  const liveNeighborCounts = tallyLiveNeighbors(cells);
37	
38	  const survivesOrIsBorn = (key: string, liveNeighbors: number): boolean =>
39	    liveNeighbors === 3 || (liveNeighbors === 2 && liveKeys.has(key));
40	
41	  return Array.from(liveNeighborCounts)
42	    .filter(([key, count]) => survivesOrIsBorn(key, count))
43	    .map(([key]) => keyToCell(key));
44	}
